@startuml

class User {
  -id: integer
  -name: string
  +getId(): integer
  +getName(): string
}

class Employee {
  -position: string
  +getPosition(): string
}

class Owner {
  -balance: integer
  +getBalance(): integer
}

class CakeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

class CoffeeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

interface StoreInterface <<interface>> {
  +getStoreName(): string
  +getOwnerName(): string
  +getEmployees(): []Employee
}

class MainStore {
  +storeInterface: StoreInterface
}

User <|-- Employee
User <|-- Owner

CakeStore "1" o-- "1" Owner
CakeStore "1" *-- "many" Employee

CoffeeStore "1" *-- "1" Owner
CoffeeStore "1" o-- "many" Employee

CakeStore ..|> StoreInterface
CoffeeStore ..|> StoreInterface

MainStore --|> StoreInterface

@enduml
